FORUM_POST_FORMAT = "<h2>{title}</h2><p>{post_body}</p>{options_list}"

def generate_post_html(title: str, content: str) -> str:
    return f"<div><h2>{title}</h2><p>{content}</p></div>"

def format_options_html(options: list[str]) -> str:
    items = ''.join(f"<li>{option}</li>" for option in options)
    return f"<ul>{items}</ul>"

def build_forum_post(title: str, post_body: str, options_list: list[str]) -> str:
    options_html = format_options_html(options_list)
    return FORUM_POST_FORMAT.format(title=title, post_body=post_body, options_list=options_html)

turn2_code:
def format_post_with_points(title: str, body: str, points: list[str]) -> str:
    points_str = ""
    if points:
        points_str = "\n" + "\n".join(f"- {p}" for p in points)
    return f"Title: {title}, Body: {body}, Points:{points_str}"

turn3_code:
import html

FORUM_POST_FORMAT = "<h2>{title}</h2><p>{post_body}</p>{options_list}"

def build_forum_post(title: str, post_body: str, options_list: list[str]) -> str:
    safe_title = html.escape(title, quote=True)
    safe_body = html.escape(post_body, quote=True)

    options_html = ""
    if options_list:
        items_html = "".join(f"<li>{html.escape(str(item), quote=True)}</li>" for item in options_list)
        options_html = f"<ul>{items_html}</ul>"

    return FORUM_POST_FORMAT.format(title=safe_title, post_body=safe_body, options_list=options_html)
